namespace sv_0f2d2e2032f74b06a26327864157a52d.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_0f2d2e2032f74b06a26327864157a52d.Components.Pages.Settings

<nav class="settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
            <span class="sidebar-icon">@GetIcon(section)</span>
            <span class="sidebar-label">@section</span>
        </button>
    }
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_0f2d2e2032f74b06a26327864157a52d.Components.Pages.Settings
@using sv_0f2d2e2032f74b06a26327864157a52d.Services

<div class="settings-section">
    <h2>Profile Settings</h2>

    <div class="avatar-preview">
        <img src="@AvatarUrl" alt="Avatar" class="avatar-image" />
        <p class="avatar-url">@AvatarUrl</p>
    </div>

    <div class="form-group">
        <label for="displayName">Display Name</label>
        <input id="displayName" type="text" @bind="DisplayName" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="email">Email</label>
        <input id="email" type="email" @bind="Email" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="bio">Bio</label>
        <textarea id="bio" rows="4" @bind="Bio" @bind:event="oninput"></textarea>
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (ShowSuccess)
    {
        <div class="toast success">Profile saved successfully!</div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private string Bio { get; set; } = "";
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideToastAsync();
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
    }
}

@namespace sv_0f2d2e2032f74b06a26327864157a52d.Components.Pages.Settings
@using sv_0f2d2e2032f74b06a26327864157a52d.Services

<div class="settings-section">
    <h2>Notification Preferences</h2>

    <div class="toggle-group">
        <label class="toggle-item">
            <input type="checkbox" @bind="EmailNotifications" />
            <span class="toggle-label">Email Notifications</span>
        </label>

        <label class="toggle-item">
            <input type="checkbox" @bind="PushNotifications" />
            <span class="toggle-label">Push Notifications</span>
        </label>

        <label class="toggle-item">
            <input type="checkbox" @bind="WeeklyDigest" />
            <span class="toggle-label">Weekly Digest</span>
        </label>
    </div>

    <h3>Muted Channels</h3>
    <div class="channel-list">
        @foreach (var channel in AvailableChannels)
        {
            <label class="channel-item">
                <input type="checkbox"
                       checked="@IsChannelMuted(channel)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <span>@channel</span>
            </label>
        }
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Preferences")
        </button>
    </div>

    @if (ShowSuccess)
    {
        <div class="toast success">Preferences saved successfully!</div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private List<string> MutedChannels { get; set; } = [];
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    private static readonly string[] AvailableChannels = ["General", "Announcements", "Engineering", "Design", "Marketing", "Support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private bool _initialized;

    private bool IsChannelMuted(string channel) => MutedChannels.Contains(channel);

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideToastAsync();
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }
}

@namespace sv_0f2d2e2032f74b06a26327864157a52d.Components.Pages.Settings
@using sv_0f2d2e2032f74b06a26327864157a52d.Services

<div class="settings-section">
    <h2>Security Settings</h2>

    <!-- Change Password Panel -->
    <div class="expandable-panel">
        <button class="panel-header" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
            <span>Change Password</span>
            <span class="expand-icon">@(PasswordPanelOpen ? "▼" : "▶")</span>
        </button>

        @if (PasswordPanelOpen)
        {
            <div class="panel-content">
                <div class="form-group">
                    <label for="currentPassword">Current Password</label>
                    <input id="currentPassword" type="password" @bind="CurrentPassword" />
                </div>
                <div class="form-group">
                    <label for="newPassword">New Password</label>
                    <input id="newPassword" type="password" @bind="NewPassword" />
                </div>
                <div class="form-group">
                    <label for="confirmPassword">Confirm Password</label>
                    <input id="confirmPassword" type="password" @bind="ConfirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(PasswordError))
                {
                    <div class="error-message">@PasswordError</div>
                }
                @if (PasswordSuccess)
                {
                    <div class="toast success">Password updated successfully!</div>
                }

                <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@IsChangingPassword">
                    @(IsChangingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="twofa-section">
        <h3>Two-Factor Authentication</h3>
        <div class="twofa-status">
            <span class="status-indicator @(TwoFactorEnabled ? "enabled" : "disabled")">
                @(TwoFactorEnabled ? "✓ Enabled" : "✗ Disabled")
            </span>
            <label class="toggle-item">
                <input type="checkbox" @bind="TwoFactorEnabled" />
                <span class="toggle-label">Enable 2FA</span>
            </label>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <p class="info-text">Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
        }
    </div>

    <!-- Active Sessions -->
    <div class="sessions-section">
        <h3>Active Sessions</h3>
        @if (Settings?.Sessions is { Count: > 0 })
        {
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Settings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session != Settings.Sessions[0])
                                {
                                    <button class="btn btn-danger btn-sm"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p>No active sessions found.</p>
        }
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (SessionToRevoke is not null)
    {
        <div class="dialog-overlay">
            <div class="dialog">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@SessionToRevoke.Device</strong> from <strong>@SessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool PasswordPanelOpen { get; set; }
    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private string? PasswordError { get; set; }
    private bool PasswordSuccess { get; set; }
    private bool IsChangingPassword { get; set; }
    private bool TwoFactorEnabled { get; set; }
    private ActiveSession? SessionToRevoke { get; set; }

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private bool _initialized;

    private async Task ChangePasswordAsync()
    {
        PasswordError = null;
        PasswordSuccess = false;

