<div class="settings-section">
    <h2>Security Settings</h2>

    <!-- Change Password Panel -->
    <div class="expandable-panel">
        <button class="panel-header" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
            <span>Change Password</span>
            <span class="expand-icon">@(PasswordPanelOpen ? "▼" : "▶")</span>
        </button>

        @if (PasswordPanelOpen)
        {
            <div class="panel-content">
                <div class="form-group">
                    <label for="currentPassword">Current Password</label>
                    <input id="currentPassword" type="password" @bind="CurrentPassword" />
                </div>
                <div class="form-group">
                    <label for="newPassword">New Password</label>
                    <input id="newPassword" type="password" @bind="NewPassword" />
                </div>
                <div class="form-group">
                    <label for="confirmPassword">Confirm Password</label>
                    <input id="confirmPassword" type="password" @bind="ConfirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(PasswordError))
                {
                    <div class="error-message">@PasswordError</div>
                }
                @if (PasswordSuccess)
                {
                    <div class="toast success">Password updated successfully!</div>
                }

                <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@IsChangingPassword">
                    @(IsChangingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="twofa-section">
        <h3>Two-Factor Authentication</h3>
        <div class="twofa-status">
            <span class="status-indicator @(TwoFactorEnabled ? "enabled" : "disabled")">
                @(TwoFactorEnabled ? "✓ Enabled" : "✗ Disabled")
            </span>
            <label class="toggle-item">
                <input type="checkbox" @bind="TwoFactorEnabled" />
                <span class="toggle-label">Enable 2FA</span>
            </label>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <p class="info-text">Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
        }
    </div>

    <!-- Active Sessions -->
    <div class="sessions-section">
        <h3>Active Sessions</h3>
        @if (Settings?.Sessions is { Count: > 0 })
        {
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Settings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session != Settings.Sessions[0])
                                {
                                    <button class="btn btn-danger btn-sm"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p>No active sessions found.</p>
        }
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (SessionToRevoke is not null)
    {
        <div class="dialog-overlay">
            <div class="dialog">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@SessionToRevoke.Device</strong> from <strong>@SessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

