+    </div>
+
+    <div class="form-group">
+        <label for="email">Email</label>
+        <input id="email" type="email" @bind="Email" @bind:event="oninput" />
+    </div>
+
+    <div class="form-group">
+        <label for="bio">Bio</label>
+        <textarea id="bio" rows="4" @bind="Bio" @bind:event="oninput"></textarea>
+    </div>
+
+    <div class="button-group">
+        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
+            @(IsSaving ? "Saving..." : "Save Changes")
+        </button>
+        <button class="btn btn-secondary" @onclick="Discard">Discard Changes</button>
+    </div>
+
+    @if (ShowSuccess)
+    {
+        <div class="toast success">Profile saved successfully!</div>
+    }
+</div>
+
+@code {
+    [Parameter] public UserProfile? Profile { get; set; }
+    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }
+
+    private string DisplayName { get; set; } = "";
+    private string Email { get; set; } = "";
+    private string AvatarUrl { get; set; } = "";
+    private string Bio { get; set; } = "";
+    private bool IsSaving { get; set; }
+    private bool ShowSuccess { get; set; }
+
+    protected override void OnParametersSet()
+    {
+        if (Profile is not null && !_initialized)
+        {
+            LoadFromProfile(Profile);
+            _initialized = true;
+        }
+    }
+
+    private bool _initialized;
+
+    private void LoadFromProfile(UserProfile profile)
+    {
+        DisplayName = profile.DisplayName;
+        Email = profile.Email;
+        AvatarUrl = profile.AvatarUrl;
+        Bio = profile.Bio;
+    }
+
+    private async Task SaveAsync()
+    {
+        IsSaving = true;
+        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
+        await OnSave.InvokeAsync(updated);
+        IsSaving = false;
+        ShowSuccess = true;
+        _ = HideToastAsync();
+    }
+
