@namespace sv_0f2d2e2032f74b06a26327864157a52d.Components.Pages.Settings
@using sv_0f2d2e2032f74b06a26327864157a52d.Services

<div class="settings-section">
    <h2>Appearance Settings</h2>

    <div class="form-group">
        <label>Theme</label>
        <div class="radio-group">
            @foreach (var theme in Themes)
            {
                <label class="radio-item">
                    <input type="radio" name="theme" value="@theme"
                           checked="@(SelectedTheme == theme)"
                           @onchange="() => SelectedTheme = theme" />
                    <span>@theme</span>
                </label>
            }
        </div>
    </div>

    <div class="form-group">
        <label>Font Size</label>
        <div class="radio-group">
            @foreach (var size in FontSizes)
            {
                <label class="radio-item">
                    <input type="radio" name="fontSize" value="@size"
                           checked="@(SelectedFontSize == size)"
                           @onchange="() => SelectedFontSize = size" />
                    <span>@size</span>
                </label>
            }
        </div>
    </div>

    <div class="form-group">
        <label for="language">Language</label>
        <select id="language" @bind="SelectedLanguage">
            @foreach (var lang in Languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <div class="form-group">
        <label class="toggle-item">
            <input type="checkbox" @bind="CompactMode" />
            <span class="toggle-label">Compact Mode</span>
        </label>
    </div>

    <!-- Live Preview -->
    <div class="preview-area @GetPreviewClasses()">
        <h4>Live Preview</h4>
        <p class="preview-text">This is how your content will look with the selected settings.</p>
        <div class="preview-card">
            <strong>Sample Card</strong>
            <p>Theme: @SelectedTheme | Font: @SelectedFontSize | Language: @SelectedLanguage</p>
        </div>
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save")
        </button>
    </div>

    @if (ShowSuccess)
    {
        <div class="toast success">Appearance settings saved!</div>
    }
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string SelectedTheme { get; set; } = "System";
    private string SelectedFontSize { get; set; } = "Medium";
    private string SelectedLanguage { get; set; } = "English";
    private bool CompactMode { get; set; }
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            SelectedTheme = Settings.Theme;
            SelectedFontSize = Settings.FontSize;
            SelectedLanguage = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private bool _initialized;

    private string GetPreviewClasses()
    {
        var classes = $"theme-{SelectedTheme.ToLowerInvariant()} font-{SelectedFontSize.ToLowerInvariant()}";
        if (CompactMode) classes += " compact";
        return classes;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideToastAsync();
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }
}

