namespace sv_0f2d2e2032f74b06a26327864157a52d.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@page "/settings"
@using sv_0f2d2e2032f74b06a26327864157a52d.Services
@using sv_0f2d2e2032f74b06a26327864157a52d.Components.Pages.Settings
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="SetActiveSection" />

    <main class="settings-content">
        @if (_isLoading)
        {
            <div class="loading">Loading settings...</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection Settings="@_securitySettings"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearanceSettings" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _isLoading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettingsAsync();
    }

    private async Task LoadAllSettingsAsync()
    {
        _isLoading = true;

        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = await profileTask;
        _notificationPrefs = await notifTask;
        _securitySettings = await securityTask;
        _appearanceSettings = await appearanceTask;

        _isLoading = false;
    }

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string currentPassword, string newPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.currentPassword, args.newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
    }
}

