{"file_text": ".settings-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 240px;
    background: var(--sidebar-bg, #f8f9fa);
    border-right: 1px solid var(--border-color, #dee2e6);
    padding: 1rem 0;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    border: none;
    background: none;
    cursor: pointer;
    font-size: 0.95rem;
    color: var(--text-color, #495057);
    text-align: left;
    width: 100%;
    transition: background 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background: var(--hover-bg, #e9ecef);
}

.sidebar-item.active {
    background: var(--active-bg, #0d6efd);
    color: #fff;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Main Content */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    font-weight: 600;
}

.settings-section h3 {
    margin-top: 1.5rem;
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
    font-weight: 600;
}

/* Form Elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: var(--label-color, #495057);
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="password"],
.form-group textarea,
.form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid var(--border-color, #dee2e6);
    border-radius: 0.375rem;
    font-size: 0.95rem;
    transition: border-color 0.15s;
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: #0d6efd;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.15);
}

/* Buttons */
.button-group {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s, opacity 0.15s;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-primary {
    background: #0d6efd;
    color: #fff;
}

.btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-secondary {
    background: #6c757d;
    color: #fff;
}

.btn-secondary:hover:not(:disabled) {
    background: #5c636a;
}

.btn-danger {
    background: #dc3545;
    color: #fff;
}

.btn-danger:hover:not(:disabled) {
    background: #bb2d3b;
}

.btn-sm {
    padding: 0.3rem 0.75rem;
    font-size: 0.8rem;
}

/* Toggle/Checkbox Items */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.toggle-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    cursor: pointer;
}

.toggle-item input[type="checkbox"] {
    width: 1.1rem;
    height: 1.1rem;
    accent-color: #0d6efd;
}

.toggle-label {
    font-size: 0.95rem;
}

/* Channel List */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.75rem;
    border: 1px solid var(--border-color, #dee2e6);
    border-radius: 0.375rem;
    max-height: 200px;
    overflow-y: auto;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

/* Avatar */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: var(--card-bg, #f8f9fa);
    border-radius: 0.5rem;
}

.avatar-image {
    width: 64px;
    height: 64px;
    border-radius: 50%;
    object-fit: cover;
    background: #dee2e6;
}

.avatar-url {
    font-size: 0.8rem;
    color: #6c757d;
    word-break: break-all;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid var(--border-color, #dee2e6);
    border-radius: 0.375rem;
    margin-bottom: 1.5rem;
}

.panel-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border: none;
    background: var(--card-bg, #f8f9fa);
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 500;
}

.panel-content {
    padding: 1rem;
    border-top: 1px solid var(--border-color, #dee2e6);
}

/* Two-Factor Auth */
.twofa-section {
    margin-bottom: 1.5rem;
}

.twofa-status {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.status-indicator {
    padding: 0.25rem 0.75rem;
    border-radius: 1rem;
    font-size: 0.85rem;
    font-weight: 500;
}

.status-indicator.enabled {
    background: #d1e7dd;
    color: #0f5132;
}

.status-indicator.disabled {
    background: #f8d7da;
    color: #842029;
}

.info-text {
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.5rem;
}

/* Sessions Table */
.sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0.5rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.6rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid var(--border-color, #dee2e6);
    font-size: 0.9rem;
}

.sessions-table th {
    font-weight: 600;
    background: var(--card-bg, #f8f9fa);
}

.current-badge {
    font-size: 0.8rem;
    padding: 0.2rem 0.5rem;
    background: #cff4fc;
    color: #055160;
    border-radius: 0.25rem;
}

/* Dialog */
.dialog-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.dialog {
    background: #fff;
    border-radius: 0.5rem;
    padding: 1.5rem;
    max-width: 400px;
    width: 90%;
    box-shadow: 0 10px 25px rgba(0, 0, 0, 0.2);
}

.dialog h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
}

.dialog-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
    justify-content: flex-end;
}

/* Radio Group */
.radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

.radio-item input[type="radio"] {
    accent-color: #0d6efd;
}

/* Appearance Preview */
.preview-area {
    margin-top: 1.5rem;
    padding: 1.25rem;
    border: 1px solid var(--border-color, #dee2e6);
    border-radius: 0.5rem;
    transition: all 0.2s;
}

.preview-area.theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-area.theme-dark {
    background: #1a1a2e;
    color: #e0e0e0;
}

.preview-area.theme-system {
    background: #f0f0f0;
    color: #333;
}

.preview-area.font-small {
    font-size: 0.8rem;
}

.preview-area.font-medium {
    font-size: 1rem;
}

.preview-area.font-large {
    font-size: 1.2rem;
}

.preview-area.compact {
    padding: 0.6rem;
    line-height: 1.2;
}

.preview-card {
    margin-top: 0.75rem;
    padding: 0.75rem;
    border: 1px solid currentColor;
    border-radius: 0.375rem;
    opacity: 0.8;
}

/* Toast */
.toast {
    margin-top: 1rem;
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    animation: fadeIn 0.3s ease-in;
