namespace sv_0f2d2e2032f74b06a26327864157a52d.Services;

/// <summary>
/// In-memory stub implementation for development/demo purposes.
/// Replace with a real implementation backed by a database or API.
/// </summary>
public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new("Jane Doe", "jane@example.com", "https://i.pravatar.cc/150?u=jane", "Software developer and open source enthusiast.");
    private NotificationPrefs _notifPrefs = new(true, true, false, ["Marketing"]);
    private SecuritySettings _security = new(
        true,
        DateTime.UtcNow.AddDays(-30),
        [
            new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
            new("sess-2", "Firefox on macOS", "London, UK", DateTime.UtcNow.AddHours(-2)),
            new("sess-3", "Mobile App (iOS)", "Tokyo, JP", DateTime.UtcNow.AddDays(-1))
        ]);
    private AppearanceSettings _appearance = new("System", "Medium", "English", false);

    public Task<UserProfile> GetProfileAsync() => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() => Task.FromResult(_notifPrefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notifPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() => Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var updatedSessions = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = updatedSessions };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

